-- Base each demo car at a random active branch of its own company (~85%);
-- the rest stay at Main. Requires migration 031 (cars.branch_id).
UPDATE cars c
SET branch_id = (
  SELECT b.id FROM branches b
  WHERE b.company_id = c.company_id AND b.is_active = TRUE
  ORDER BY random() LIMIT 1)
WHERE c.vin LIKE 'DMO%' AND random() < 0.85;
COMMIT;

SELECT co.companyid, co.companyname, COUNT(c.id) AS cars
FROM companies co JOIN cars c ON c.company_id = co.id AND c.is_active
WHERE c.vin LIKE 'DMO%'
GROUP BY co.companyid, co.companyname ORDER BY cars DESC;